To make the `get`, `put`, `size`, and `clear` methods thread-safe, we can utilize a mutex to ensure synchronization during concurrent access. Here’s an updated version of the `include/lru_cache.hpp` file with the necessary changes:

```cpp
```cpp file=include/lru_cache.hpp
#pragma once
#include <cstddef>
#include <list>
#include <mutex>
#include <optional>
#include <unordered_map>
#include <utility>

template <typename K, typename V>
class LRUCache {
public:
    explicit LRUCache(size_t capacity) : capacity_(capacity) {}

    std::optional<V> get(const K& key) {
        std::lock_guard<std::mutex> lock(mutex_);  // Lock the mutex
        auto it = map_.find(key);
        if (it == map_.end()) return std::nullopt;
        list_.splice(list_.begin(), list_, it->second);
        return it->second->second;
    }

    void put(const K& key, V value) {
        std::lock_guard<std::mutex> lock(mutex_);  // Lock the mutex
        auto it = map_.find(key);
        if (it != map_.end()) {
            list_.splice(list_.begin(), list_, it->second);
            it->second->second = std::move(value);
            return;
        }
        while (list_.size() >= capacity_) {  // Correct eviction condition
            auto last = std::prev(list_.end());
            map_.erase(last->first);
            list_.erase(last);
        }
        list_.emplace_front(key, std::move(value));
        map_[key] = list_.begin();
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mutex_);  // Lock the mutex
        return list_.size();
    }

    void clear() {
        std::lock_guard<std::mutex> lock(mutex_);  // Lock the mutex
        list_.clear();
        map_.clear();
    }

private:
    size_t capacity_;
    std::list<std::pair<K, V>> list_;
    std::unordered_map<K, typename std::list<std::pair<K, V>>::iterator> map_;
    mutable std::mutex mutex_;  // Mutex for thread safety
};
```

In this updated code:
- A `std::mutex` named `mutex_` is added to handle synchronization.
- Each method acquires a lock using `std::lock_guard` to ensure that only one thread can access the cache's data structure at a time.
- The eviction condition in `put` is fixed to check `>=` to prevent exceeding capacity.

